#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <algorithm>
#include <cctype>

// Declare the user's solution_main function
extern int solution_main(); 

// Helper to trim and normalize string output for comparison
std::string trim_and_normalize(const std::string& str) {
    std::string s = str;
    // Remove carriage returns
    s.erase(std::remove(s.begin(), s.end(), '\r'), s.end());
    // Trim leading and trailing whitespace
    size_t first = s.find_first_not_of(" \t\n");
    if (std::string::npos == first) {
        return "";
    }
    size_t last = s.find_last_not_of(" \t\n");
    return s.substr(first, (last - first + 1));
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"2\n20\n", "2 3 5 7 11 13 17 19"},
        {"20\n2\n", ""}, 
        {"-5\n10\n", "2 3 5 7"},
        {"0\n1\n", ""},
        {"11\n11\n", "11"}
    };

    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::string input = test_cases[i].first;
        std::string expected_output = test_cases[i].second;

        std::stringstream ss_in(input);
        std::stringstream ss_out;

        // Redirect std::cin and std::cout
        std::streambuf* old_cin = std::cin.rdbuf();
        std::streambuf* old_cout = std::cout.rdbuf();
        std::cin.rdbuf(ss_in.rdbuf());
        std::cout.rdbuf(ss_out.rdbuf());

        // Call the user's solution function
        solution_main();

        // Restore std::cin and std::cout
        std::cin.rdbuf(old_cin);
        std::cout.rdbuf(old_cout);

        std::string actual_output = trim_and_normalize(ss_out.str());
        std::string normalized_expected = trim_and_normalize(expected_output);

        if (actual_output != normalized_expected) {
            std::cerr << "Test Case " << i + 1 << " Failed!\n";
            std::cerr << "Input:\n" << input << "\n";
            std::cerr << "Expected:\n" << normalized_expected << "\n";
            std::cerr << "Actual:\n" << actual_output << "\n";
            return 1; // Indicate failure
        }
    }
    return 0; // Indicate success
}
